const incoming = $input.first()?.json;
if (Array.isArray(incoming?.entries)) return [{json: incoming}];
return [{json:{batch_id:'cal35-manual-test',approved:false,mode:'draft',privacy:'SELF_ONLY',publish_at:new Date(Date.now()+60000).toISOString(),entries:[{word:'resilient',ipa:'/rɪˈzɪl.i.ənt/',part_of_speech:'adjective',meaning_vi:'kiên cường',example_en:'She stayed resilient after the setback.',example_vi:'Cô ấy vẫn kiên cường sau trở ngại.',cta:'Follow @english.daily.vn để học 1 từ mỗi ngày.',channel_handle:'@english.daily.vn',duration_seconds:10,template_key:'vocabulary-pastel-v1'}]}}];

const body=$input.first().json; const entries=body.entries;
if(!Array.isArray(entries)||entries.length<1||entries.length>50) throw new Error('NON_RETRYABLE: entries must contain 1-50 items');
if(!/^[A-Za-z0-9][A-Za-z0-9._-]{7,127}$/.test(body.batch_id||'')) throw new Error('NON_RETRYABLE: batch_id must be 8-128 URL-safe characters');
const publishAt=new Date(body.publish_at); if(Number.isNaN(publishAt.getTime())) throw new Error('NON_RETRYABLE: publish_at must be ISO-8601');
return entries.map((entry,index)=>{ for(const key of ['word','ipa','part_of_speech','meaning_vi','example_en','example_vi','cta','channel_handle','template_key']) if(typeof entry[key]!=='string'||!entry[key].trim()) throw new Error(`NON_RETRYABLE: entries[${index}].${key} is required`); return {json:{...entry,batch_id:body.batch_id,job_id:`${body.batch_id}-${String(index+1).padStart(2,'0')}`,approved:body.approved===true,mode:body.mode==='publish'?'publish':'draft',privacy:'SELF_ONLY',publish_at:publishAt.toISOString()}};});
